import axios from 'axios';

const apiUrl = "http://localhost:5001"

export default {
  getTasks: async () => {
    const result = await axios.get(`${apiUrl}/items`)    
    return result.data;
  },

 // הוספת משימה חדשה
  addTask: async (name) => {
    console.log('addTask', name);
    // אובייקט המשימה שצריך לשלוח לשרת
    const result = await axios.post(`${apiUrl}/items`, {
      name: name,
      isComplete: false
    });
    return result.data;
  },

  // עדכון מצב משימה (הושלם/לא הושלם)
  setCompleted: async (id, isComplete) => {
    console.log('setCompleted', { id, isComplete });
    // אנחנו שולחים PUT לנתיב items/{id}
    // ב-Minimal API שבנינו, השרת מצפה לאובייקט Item שלם ב-Body
    const result = await axios.put(`${apiUrl}/items/${id}`, {
      id: id,
      name: "", // אפשר לשלוח ריק או את השם המקורי אם נשמר, השרת מעדכן לפי ה-ID
      isComplete: isComplete
    });
    return result.data;
  },

  // מחיקת משימה
  deleteTask: async (id) => {
    console.log('deleteTask', id);
    const result = await axios.delete(`${apiUrl}/items/${id}`);
    return result.data;
  }
};
